import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Badge,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  electronConfiguration: string;
  row: number;
  col: number;
}

interface Props {
  elements: Element[];
}

const categoryColorMap: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline-earth': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition-metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition-metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  'metalloid': 'var(--ggui-color-warning-300, #fcd34d)',
  'nonmetal': 'var(--ggui-color-success-500, #22c55e)',
  'halogen': 'var(--ggui-color-success-300, #86efac)',
  'noble-gas': 'var(--ggui-color-primary-600, #0284c7)',
  'lanthanide': 'var(--ggui-color-primary-400, #38bdf8)',
  'actinide': 'var(--ggui-color-error-300, #fca5a5)',
};

const categoryLabelMap: Record<string, string> = {
  'alkali-metal': 'Alkali Metal',
  'alkaline-earth': 'Alkaline Earth',
  'transition-metal': 'Transition Metal',
  'post-transition-metal': 'Post-Transition Metal',
  'metalloid': 'Metalloid',
  'nonmetal': 'Nonmetal',
  'halogen': 'Halogen',
  'noble-gas': 'Noble Gas',
  'lanthanide': 'Lanthanide',
  'actinide': 'Actinide',
};

export default function PeriodicTable({ elements }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = elements.filter((el) =>
    el.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    el.symbol.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const uniqueCategories = Array.from(
    new Set(elements.map((el) => el.category))
  ).sort();

  const getCategoryColor = (category: string): string => {
    return categoryColorMap[category] || 'var(--ggui-color-primary-300, #7dd3fc)';
  };

  const getSelectedBorder = (atomicNumber: number): string => {
    if (selectedElement?.atomicNumber === atomicNumber) {
      return '3px solid var(--ggui-color-primary-700, #0369a1)';
    }
    return '1px solid var(--ggui-color-outline, #d4d4d8)';
  };

  const getSelectedShadow = (atomicNumber: number): string => {
    if (selectedElement?.atomicNumber === atomicNumber) {
      return '0 4px 12px var(--ggui-color-onSurface, #18181b)';
    }
    return 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack direction="vertical" gap={24}>
        <div>
          <Text variant="h1" align="left">
            Interactive Periodic Table
          </Text>
          <Text
            variant="body"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="left"
          >
            Click on an element to see detailed information
          </Text>
        </div>

        <div>
          <Text variant="label" weight="semibold" style={{ display: 'block', marginBottom: '8px' }}>
            Search Elements
          </Text>
          <input
            type="text"
            placeholder="e.g., 'gold' or 'Au'"
            value={searchQuery}
            onChange={setSearchQuery}
            style={{
              width: '100%',
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              backgroundColor: 'var(--ggui-color-surface, #fafafa)',
              color: 'var(--ggui-color-onSurface, #18181b)',
              fontSize: '16px',
              fontFamily: 'inherit',
            }}
          />
        </div>

        <Card padding={16} border={true}>
          <Stack direction="vertical" gap={12}>
            <Text variant="label" weight="semibold">
              Element Categories
            </Text>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(150px, 1fr))',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {uniqueCategories.map((category) => (
                <Row key={category} gap={8} align="center">
                  <div
                    style={{
                      width: '20px',
                      height: '20px',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      backgroundColor: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                    }}
                  />
                  <Text variant="caption">
                    {categoryLabelMap[category]}
                  </Text>
                </Row>
              ))}
            </div>
          </Stack>
        </Card>

        <Card
          padding={24}
          border={true}
          shadow="sm"
          style={{ overflowX: 'auto' }}
        >
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '100%',
            }}
          >
            {filteredElements.map((element) => (
              <div
                key={String(element.atomicNumber)}
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                <button
                  onClick={() => setSelectedElement(element)}
                  style={{
                    width: '100%',
                    aspectRatio: '1',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    backgroundColor: getCategoryColor(element.category),
                    border: getSelectedBorder(element.atomicNumber),
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                    boxShadow: getSelectedShadow(element.atomicNumber),
                  }}
                  onMouseEnter={(e) => {
                    if (selectedElement?.atomicNumber !== element.atomicNumber) {
                      e.currentTarget.style.boxShadow =
                        'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (selectedElement?.atomicNumber !== element.atomicNumber) {
                      e.currentTarget.style.boxShadow = getSelectedShadow(element.atomicNumber);
                    }
                  }}
                >
                  <Text
                    variant="caption"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                      fontSize: '10px',
                    }}
                  >
                    {element.atomicNumber}
                  </Text>

                  <Text
                    variant="h3"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                  >
                    {element.symbol}
                  </Text>

                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                    style={{ fontSize: '9px', marginTop: 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {element.name}
                  </Text>
                </button>
              </div>
            ))}
          </div>
        </Card>

        {selectedElement && (
          <Card
            padding={24}
            border={true}
            shadow="md"
            style={{
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderLeft: '6px solid ' + getCategoryColor(selectedElement.category),
            }}
          >
            <Stack direction="vertical" gap={16}>
              <Row justify="between" align="center">
                <div>
                  <Text variant="h2">{selectedElement.name}</Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {categoryLabelMap[selectedElement.category]}
                  </Text>
                </div>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Row>

              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: 'var(--ggui-spacing-4, 16px)',
                }}
              >
                <div
                  style={{
                    padding: 'var(--ggui-spacing-2, 8px)',
                    backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Text
                    variant="caption"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Atomic Number
                  </Text>
                  <Text variant="h3" weight="bold">
                    {selectedElement.atomicNumber}
                  </Text>
                </div>

                <div
                  style={{
                    padding: 'var(--ggui-spacing-2, 8px)',
                    backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Text
                    variant="caption"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Symbol
                  </Text>
                  <Text variant="h3" weight="bold">
                    {selectedElement.symbol}
                  </Text>
                </div>

                <div
                  style={{
                    padding: 'var(--ggui-spacing-2, 8px)',
                    backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Text
                    variant="caption"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Atomic Weight
                  </Text>
                  <Text variant="h3" weight="bold">
                    {selectedElement.atomicWeight.toFixed(2)}
                  </Text>
                </div>
              </div>

              <div
                style={{
                  padding: 'var(--ggui-spacing-2, 8px)',
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                }}
              >
                <Text
                  variant="caption"
                  weight="semibold"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Electron Configuration
                </Text>
                <Text
                  variant="body"
                  style={{
                    marginTop: 'var(--ggui-spacing-2, 8px)',
                    wordBreak: 'break-word',
                    fontFamily: 'monospace',
                  }}
                >
                  {selectedElement.electronConfiguration}
                </Text>
              </div>

              <div>
                <Text
                  variant="caption"
                  weight="semibold"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  style={{ display: 'block', marginBottom: 'var(--ggui-spacing-2, 8px)' }}
                >
                  Category
                </Text>
                <Badge variant="primary" size="md">
                  {categoryLabelMap[selectedElement.category]}
                </Badge>
              </div>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}
